import React, { useState, useRef } from 'react';
import { generateMovieMetadata } from '../services/geminiService';
import { Movie } from '../types';

interface UploadModalProps {
  isOpen: boolean;
  onClose: () => void;
  onUploadSuccess: (newMovie: Movie) => void;
}

const UploadModal: React.FC<UploadModalProps> = ({ isOpen, onClose, onUploadSuccess }) => {
  const [file, setFile] = useState<File | null>(null);
  const [prompt, setPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [progress, setProgress] = useState(0);
  const fileInputRef = useRef<HTMLInputElement>(null);

  if (!isOpen) return null;

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFile(e.target.files[0]);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!file) return;

    setIsGenerating(true);
    setProgress(20);

    // AI Metadata Generation
    const metadata = await generateMovieMetadata(file.name, prompt);
    setProgress(60);

    // Simulate "uploading"
    setTimeout(() => {
      setProgress(100);
      const newMovie: Movie = {
        id: Math.random().toString(36).substr(2, 9),
        title: metadata?.title || file.name.split('.')[0],
        description: metadata?.description || 'A video uploaded by the user.',
        category: metadata?.category || 'User Uploads',
        thumbnailUrl: `https://picsum.photos/seed/${Math.random()}/800/450`,
        videoUrl: URL.createObjectURL(file), // Using local URL for simulation
        duration: '0:00', // In a real app we'd extract this
        year: new Date().getFullYear(),
        rating: 'NR',
        isUserUploaded: true
      };

      onUploadSuccess(newMovie);
      setIsGenerating(false);
      onClose();
      // Reset state
      setFile(null);
      setPrompt('');
      setProgress(0);
    }, 1500);
  };

  return (
    <div className="fixed inset-0 z-[60] bg-black/80 flex items-center justify-center p-4">
      <div className="bg-zinc-900 border border-zinc-800 w-full max-w-lg rounded-lg shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300">
        <div className="p-6 border-b border-zinc-800 flex justify-between items-center">
          <h2 className="text-xl font-bold">Upload Your Masterpiece</h2>
          <button onClick={onClose} className="text-gray-400 hover:text-white">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-6">
          <div 
            className={`border-2 border-dashed rounded-lg p-10 flex flex-col items-center justify-center gap-4 cursor-pointer transition ${file ? 'border-green-500 bg-green-500/5' : 'border-zinc-700 hover:border-red-600 hover:bg-zinc-800'}`}
            onClick={() => fileInputRef.current?.click()}
          >
            <input 
              type="file" 
              ref={fileInputRef} 
              className="hidden" 
              accept="video/*" 
              onChange={handleFileChange} 
            />
            <svg xmlns="http://www.w3.org/2000/svg" className={`h-12 w-12 ${file ? 'text-green-500' : 'text-gray-500'}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
            </svg>
            <div className="text-center">
              <p className="font-bold">{file ? file.name : 'Select a video file'}</p>
              <p className="text-sm text-gray-400">MP4, WebM or OGG (Max 2GB)</p>
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-400 mb-2">AI Metadata Assistant (Optional)</label>
            <textarea 
              className="w-full bg-zinc-800 border border-zinc-700 rounded p-3 text-sm focus:outline-none focus:ring-2 focus:ring-red-600 transition"
              placeholder="Tell us what's in the video and Gemini will generate professional descriptions and titles..."
              rows={3}
              value={prompt}
              onChange={(e) => setPrompt(e.target.value)}
            />
          </div>

          {isGenerating && (
            <div className="space-y-2">
              <div className="flex justify-between text-xs text-gray-400 font-medium">
                <span>{progress < 50 ? 'Analyzing content...' : 'Generating AI descriptions...'}</span>
                <span>{progress}%</span>
              </div>
              <div className="w-full bg-zinc-800 rounded-full h-1.5 overflow-hidden">
                <div 
                  className="bg-red-600 h-full transition-all duration-300" 
                  style={{ width: `${progress}%` }}
                />
              </div>
            </div>
          )}

          <button 
            type="submit" 
            disabled={!file || isGenerating}
            className={`w-full py-3 rounded font-bold transition flex items-center justify-center gap-2 ${file && !isGenerating ? 'bg-red-600 hover:bg-red-700 text-white shadow-lg' : 'bg-zinc-800 text-gray-500 cursor-not-allowed'}`}
          >
            {isGenerating ? (
              <>
                <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                </svg>
                Processing...
              </>
            ) : 'Publish Video'}
          </button>
        </form>
      </div>
    </div>
  );
};

export default UploadModal;

