      alert(`Downloading ${movie.title}...`);
    } catch (err) {
      console.error('Download failed', err);
      alert('Download failed. Some sample videos might have CORS restrictions.');
    }
  };

  if (!user.isLoggedIn) {
    return <LoginScreen onLogin={handleLogin} />;
  }

  const categories = Array.from(new Set(movies.map(m => m.category)));

  return (
    <div className="min-h-screen bg-black overflow-x-hidden animate-fade-in">
      <Navbar 
        user={user} 
        onLogin={handleLogin} 
        onLogout={handleLogout}
        onUploadClick={() => setIsUploadOpen(true)}
      />

      <main>
        <Hero movie={featuredMovie} onPlay={(m) => setActiveMovie(m)} />

        <div className="relative z-20 -mt-32 pb-20 space-y-12">
          {/* My Uploads Row */}
          {movies.some(m => m.isUserUploaded) && (
            <div className="px-4 md:px-12">
              <h2 className="text-xl md:text-2xl font-bold mb-4">Your Uploads</h2>
              <div className="flex gap-2 overflow-x-auto no-scrollbar pb-4 -mx-1 px-1">
                {movies.filter(m => m.isUserUploaded).map(movie => (
                  <MovieCard 
                    key={movie.id} 
                    movie={movie} 
                    onClick={() => setActiveMovie(movie)}
                    onDownload={handleDownload}
                  />
                ))}
              </div>
            </div>
          )}

          {/* Dynamic Category Rows */}
          {categories.map(category => (
            <div key={category} className="px-4 md:px-12">
              <h2 className="text-xl md:text-2xl font-bold mb-4">{category}</h2>
              <div className="flex gap-2 overflow-x-auto no-scrollbar pb-4 -mx-1 px-1">
                {movies.filter(m => m.category === category).map(movie => (
                  <MovieCard 
                    key={movie.id} 
                    movie={movie} 
                    onClick={() => setActiveMovie(movie)}
                    onDownload={handleDownload}
                  />
                ))}
              </div>
            </div>
          ))}

          {/* Trending Row */}
          <div className="px-4 md:px-12">
            <h2 className="text-xl md:text-2xl font-bold mb-4">Trending Now</h2>
            <div className="flex gap-2 overflow-x-auto no-scrollbar pb-4 -mx-1 px-1">
              {movies.map(movie => (
                <MovieCard 
                  key={`trending-${movie.id}`} 
                  movie={movie} 
                  onClick={() => setActiveMovie(movie)}
                  onDownload={handleDownload}
                />
              ))}
            </div>
          </div>
        </div>
      </main>

      {activeMovie && (
        <VideoPlayer 
          movie={activeMovie} 
          onClose={() => setActiveMovie(null)} 
        />
      )}

      <UploadModal 
        isOpen={isUploadOpen} 
        onClose={() => setIsUploadOpen(false)}
        onUploadSuccess={handleUploadSuccess}
      />

      <footer className="bg-zinc-950 px-4 md:px-12 py-12 border-t border-zinc-900 mt-12">
        <div className="max-w-6xl mx-auto flex flex-col items-center gap-8">
          <div className="flex gap-8 text-gray-500 text-sm">
            <a href="#" className="hover:underline">Audio Description</a>
            <a href="#" className="hover:underline">Help Center</a>
            <a href="#" className="hover:underline">Gift Cards</a>
            <a href="#" className="hover:underline">Media Center</a>
          </div>
          <p className="text-gray-600 text-xs">© 1997-2024 CineStream Pro, Inc.</p>
        </div>
      </footer>
    </div>
  );
};

export default App;
